import React from 'react';
import './Header.css';

function Header({ data, onFileSelect, user, onLogout, showReport, onToggleReport }) {
  const handleFileInput = (e) => {
    if (e.target.files[0]) onFileSelect(e.target.files[0]);
  };

  return (
    <header className="header">
      <div className="header-left">
        <div className="logo">NVL</div>
        <div>
          <h1>Catalogue <span>NVL & VPP</span></h1>
        </div>
      </div>

      <div className="header-stats">
        <div>
          <div className="stat-val">{data.length}</div>
          <div>Sản phẩm</div>
        </div>
        <div>
          <div className="stat-val">{new Set(data.map(d => d.vc)).size}</div>
          <div>Khu vực</div>
        </div>
        <div>
          <div className="stat-val">{new Set(data.map(d => d.cat)).size}</div>
          <div>Danh mục</div>
        </div>
        <div>
          <div className="stat-val">{new Set(data.map(d => d.ncc)).size}</div>
          <div>NCC</div>
        </div>
      </div>

      <div className="header-right">
        {!showReport && (
          <>
            <button className="btn btn-ghost" onClick={() => document.getElementById('fileInput').click()}>
              📂 Tải file Excel
            </button>
            <input
              id="fileInput"
              type="file"
              accept=".xlsx,.xls"
              style={{ display: 'none' }}
              onChange={handleFileInput}
            />
          </>
        )}

        <button
          className={`btn ${showReport ? 'btn-primary' : 'btn-report'}`}
          onClick={onToggleReport}
        >
          {showReport ? '← Catalogue' : '📊 Báo cáo'}
        </button>

        {user && (
          <div className="header-user">
            <span className="user-avatar">{user.username.charAt(0).toUpperCase()}</span>
            <div className="user-info">
              <span className="user-name">{user.username}</span>
              <span className="user-dept">{user.khuVuc} · {user.phongBan}</span>
            </div>
            <button className="btn-logout" onClick={onLogout} title="Đăng xuất">✕</button>
          </div>
        )}
      </div>
    </header>
  );
}

export default Header;
